const db = require('./db');

function listReviews() {
  return db.prepare(`
    SELECT
      r.id,
      r.user_id,
      r.product_id,
      r.rating,
      r.title,
      r.comment,
      r.created_at,
      u.name AS user_name,
      u.email AS user_email,
      p.name AS product_name
    FROM reviews r
    JOIN users u ON r.user_id = u.id
    JOIN products p ON r.product_id = p.id
    ORDER BY r.created_at DESC
  `).all();
}

function getReviewById(id) {
  return db.prepare(`
    SELECT
      r.id,
      r.user_id,
      r.product_id,
      r.rating,
      r.title,
      r.comment,
      r.created_at,
      u.name AS user_name,
      u.email AS user_email,
      p.name AS product_name
    FROM reviews r
    JOIN users u ON r.user_id = u.id
    JOIN products p ON r.product_id = p.id
    WHERE r.id = ?
  `).all(id);
}

function createReview({ user_id, product_id, rating, title, comment }) {
  return db.prepare(`
    INSERT INTO reviews (user_id, product_id, rating, title, comment)
    VALUES (?, ?, ?, ?, ?)
  `).run(user_id, product_id, rating, title || null, comment || null);
}

function updateReview(id, { rating, title, comment }) {
  return db.prepare(`
    UPDATE reviews
    SET rating = ?, title = ?, comment = ?
    WHERE id = ?
  `).run(rating, title || null, comment || null, id);
}

function deleteReview(id) {
  return db.prepare('DELETE FROM reviews WHERE id = ?').run(id);
}

function listProducts() {
  return db.prepare('SELECT id, name FROM products ORDER BY name ASC').all();
}

function listUsers() {
  return db.prepare('SELECT id, name, email FROM users ORDER BY name ASC').all();
}

module.exports = { listReviews, getReviewById, createReview, updateReview, deleteReview, listProducts, listUsers };

