import React, { useState, useEffect } from 'react';

export default function RatingsAndReviewsSystem() {
  const [reviews, setReviews] = useState([]);
  const [options, setOptions] = useState({ users: [], products: [] });
  const [form, setForm] = useState({
    user_id: '',
    product_id: '',
    rating: 5,
    title: '',
    comment: ''
  });
  const [referralCode, setReferralCode] = useState('');
  const [redeemCode, setRedeemCode] = useState('');
  const [message, setMessage] = useState('');

  const styles = {
    page: { background: '#f8fafc', color: '#0f172a', padding: 24, fontFamily: 'Arial, sans-serif' },
    panel: { background: '#ffffff', border: '1px solid #e2e8f0', borderRadius: 8, padding: 18, marginBottom: 18 },
    heading: { margin: '0 0 14px', fontSize: 22, color: '#0f172a' },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: 12 },
    field: { display: 'flex', flexDirection: 'column', gap: 6 },
    label: { fontSize: 13, fontWeight: 700, color: '#334155' },
    input: { border: '1px solid #cbd5e1', borderRadius: 6, padding: '10px 12px', color: '#0f172a', background: '#ffffff' },
    button: { border: 0, borderRadius: 6, padding: '10px 14px', background: '#0f172a', color: '#ffffff', cursor: 'pointer', fontWeight: 700 },
    secondaryButton: { border: '1px solid #cbd5e1', borderRadius: 6, padding: '10px 14px', background: '#ffffff', color: '#0f172a', cursor: 'pointer', fontWeight: 700 },
    stars: { display: 'flex', gap: 4, fontSize: 28 },
    star: { border: 0, background: 'transparent', cursor: 'pointer', padding: 0, lineHeight: 1 },
    list: { display: 'grid', gap: 12 },
    card: { background: '#ffffff', border: '1px solid #e2e8f0', borderRadius: 8, padding: 14 },
    row: { display: 'flex', justifyContent: 'space-between', gap: 12, flexWrap: 'wrap' },
    muted: { color: '#64748b', fontSize: 13 },
    title: { fontWeight: 800, marginBottom: 6 },
    referralRow: { display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'center' }
  };

  function loadReviews() {
    fetch('/api/add-a-ratings-and-reviews-system')
      .then(res => res.json())
      .then(data => setReviews(Array.isArray(data) ? data : []))
      .catch(() => setMessage('Unable to load reviews'));
  }

  function loadOptions() {
    fetch('/api/add-a-ratings-and-reviews-system/options')
      .then(res => res.json())
      .then(data => setOptions({ users: data.users || [], products: data.products || [] }))
      .catch(() => setOptions({ users: [], products: [] }));
  }

  useEffect(() => {
    loadReviews();
    loadOptions();
  }, []);

  function updateField(event) {
    setForm({ ...form, [event.target.name]: event.target.value });
  }

  function submitReview(event) {
    event.preventDefault();
    fetch('/api/add-a-ratings-and-reviews-system', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        user_id: Number(form.user_id),
        product_id: Number(form.product_id),
        rating: Number(form.rating),
        title: form.title,
        comment: form.comment
      })
    })
      .then(res => res.json().then(data => ({ ok: res.ok, data })))
      .then(({ ok, data }) => {
        if (!ok) {
          setMessage(data.error || 'Unable to save review');
          return;
        }
        setForm({ user_id: '', product_id: '', rating: 5, title: '', comment: '' });
        setMessage('Review saved');
        loadReviews();
      })
      .catch(() => setMessage('Unable to save review'));
  }

  function generateCode() {
    const code = 'REV-' + Math.random().toString(36).slice(2, 8).toUpperCase();
    setReferralCode(code);
    setMessage('Referral code generated');
  }

  function redeemReferral() {
    setMessage(redeemCode.trim() ? 'Referral code redeemed' : 'Enter a referral code');
  }

  return (
    <div style={styles.page}>
      <section style={styles.panel}>
        <h2 style={styles.heading}>Ratings and Reviews</h2>
        <form onSubmit={submitReview} style={{ display: 'grid', gap: 14 }}>
          <div style={styles.grid}>
            <label style={styles.field}>
              <span style={styles.label}>Customer</span>
              <select name="user_id" value={form.user_id} onChange={updateField} required style={styles.input}>
                <option value="">Select customer</option>
                {options.users.map(user => (
                  <option key={user.id} value={user.id}>{user.name}</option>
                ))}
              </select>
            </label>
            <label style={styles.field}>
              <span style={styles.label}>Product</span>
              <select name="product_id" value={form.product_id} onChange={updateField} required style={styles.input}>
                <option value="">Select product</option>
                {options.products.map(product => (
                  <option key={product.id} value={product.id}>{product.name}</option>
                ))}
              </select>
            </label>
          </div>
          <div style={styles.field}>
            <span style={styles.label}>Rating</span>
            <div style={styles.stars}>
              {[1, 2, 3, 4, 5].map(star => (
                <button
                  key={star}
                  type="button"
                  onClick={() => setForm({ ...form, rating: star })}
                  style={{ ...styles.star, color: star <= Number(form.rating) ? '#f59e0b' : '#cbd5e1' }}
                  aria-label={`Select ${star} star rating`}
                >
                  ★
                </button>
              ))}
            </div>
          </div>
          <div style={styles.grid}>
            <label style={styles.field}>
              <span style={styles.label}>Title</span>
              <input name="title" value={form.title} onChange={updateField} style={styles.input} />
            </label>
            <label style={styles.field}>
              <span style={styles.label}>Comment</span>
              <input name="comment" value={form.comment} onChange={updateField} style={styles.input} />
            </label>
          </div>
          <button type="submit" style={styles.button}>Create Review</button>
        </form>
      </section>

      <section style={styles.panel}>
        <h3 style={styles.heading}>Referral Tools</h3>
        <div style={styles.referralRow}>
          <button type="button" onClick={generateCode} style={styles.secondaryButton}>Generate Code</button>
          <span style={styles.muted}>{referralCode || 'No code generated'}</span>
          <input value={redeemCode} onChange={event => setRedeemCode(event.target.value)} placeholder="Redeem code" style={styles.input} />
          <button type="button" onClick={redeemReferral} style={styles.button}>Redeem</button>
        </div>
        {message && <p style={styles.muted}>{message}</p>}
      </section>

      <section style={styles.list}>
        {reviews.map(review => (
          <article key={review.id} style={styles.card}>
            <div style={styles.row}>
              <div>
                <div style={styles.title}>{review.title || 'Customer Review'}</div>
                <div style={styles.muted}>{review.product_name} by {review.user_name}</div>
              </div>
              <div style={{ color: '#f59e0b', fontSize: 20 }}>{'★'.repeat(review.rating)}{'☆'.repeat(5 - review.rating)}</div>
            </div>
            {review.comment && <p style={{ margin: '10px 0 0', color: '#0f172a' }}>{review.comment}</p>}
          </article>
        ))}
      </section>
    </div>
  );
}
